import math
import unittest

from shapes import Circle, Rectangle, Triangle


class TestShapes(unittest.TestCase):
    def test_rectangle(self):
        self.assertAlmostEqual(Rectangle(3, 4).area(), 12.0)

    def test_triangle(self):
        self.assertAlmostEqual(Triangle(3, 4).area(), 6.0)

    def test_circle_unit(self):
        self.assertAlmostEqual(Circle(1).area(), math.pi)

    def test_circle_r2(self):
        self.assertAlmostEqual(Circle(2).area(), math.pi * 4)


if __name__ == "__main__":
    unittest.main()

import math

from .base import Shape


class Circle(Shape):
    def __init__(self, radius: float):
        self.radius = radius

    def area(self) -> float:
        # BUG: area of a circle is pi * r**2, not pi * r
        return math.pi * self.radius

from .base import Shape


class Rectangle(Shape):
    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

from .base import Shape


class Triangle(Shape):
    def __init__(self, base: float, height: float):
        self.base = base
        self.height = height

    def area(self) -> float:
        return 0.5 * self.base * self.height

from abc import ABC, abstractmethod


class Shape(ABC):
    """Base class for all shapes. Subclasses must implement area()."""

    @abstractmethod
    def area(self) -> float:
        raise NotImplementedError

    def describe(self) -> str:
        return f"{type(self).__name__} with area {self.area():.4f}"

